// Initialise une variable DemoVar pour tests (scope file)
// Définit aussi flow.varSelected = 'DemoVar'
let enriched = global.get('enrichedVars','file') || {};
if (!enriched.DemoVar) {
    enriched.DemoVar = {
        nomVarG: 'DemoVar',
        abbrVarG: 'DVar',
        descriptionVarG: 'Variable de démonstration',
        dateUpdateVarG: new Date().toISOString(),
        instances: ['*','inst1','inst2'],
        proprietes: [
            { nomP:'nom', abbrP:'nm', typeP:'string', schema:null, valeurs:{'*':'Inconnu','inst1':'Alice','inst2':'Bob'} },
            { nomP:'age', abbrP:'ag', typeP:'number', schema:null, valeurs:{'*':0,'inst1':30,'inst2':25} },
            { nomP:'actif', abbrP:'act', typeP:'boolean', schema:null, valeurs:{'*':true,'inst1':false,'inst2':true} },
            { nomP:'config', abbrP:'cfg', typeP:'object', schema:[{nomSsP:'couleur',typeSsP:'string'},{nomSsP:'intensite',typeSsP:'number'},{nomSsP:'active',typeSsP:'boolean'}], valeurs:{'*':{couleur:'red',intensite:50,active:true},'inst1':{couleur:'blue',intensite:80,active:false},'inst2':{couleur:'green',intensite:20,active:false}} }
        ]
    };
    global.set('enrichedVars', enriched, 'file');
}
flow.set('varSelected','DemoVar');
// reset selected property state
flow.set('propSelected', null);
msg.topic = 'newVarSelected';
msg.info = 'DemoVar initialisé (si absent) et sélectionné.';
return msg;

// Prépare l'objet envoyé au template principal (tableau)
// - si msg.topic indique une nouvelle sélection de variable, on reset flow.propSelected
// - construit msg.payload.proprietes (liste) et msg.payload.instances (sans '*')

let varSelected = flow.get('varSelected') || null;
let propSelected = flow.get('propSelected') || null;
let enriched = global.get('enrichedVars','file') || {};
let variable = enriched[varSelected] || {};

// Reset selected property when explicitly asked (ex: newVarSelected / selectVariable / refresh)
if (msg.topic === 'newVarSelected' || msg.topic === 'selectVariable' || msg.topic === 'refresh') {
    flow.set('propSelected', null);
    propSelected = null;
}

let proprietes = (variable.proprietes || []).map(p => ({
    nomP: p.nomP,
    abbrP: p.abbrP,
    typeP: p.typeP,
    schema: p.schema || null,
    valeurs: p.valeurs || {},
    defaut: (p.valeurs && p.valeurs['*'] !== undefined) ? p.valeurs['*'] : null,
    _locked: p._locked || false
}));

// Add a transient 'NouvelleP' placeholder row (not persisted)
proprietes.push({ nomP: 'NouvelleP', abbrP: 'New', typeP: null, schema: null, valeurs: {'*':null}, defaut: null, _isNew: true });

let instances = (variable.instances || []).filter(i => i !== '*'); // don't display '*' as a column

msg.payload = { proprietes: proprietes, instances: instances, variable: { nomVarG: variable.nomVarG || '' } };
msg.info = propSelected ? `Propriété sélectionnée : ${propSelected}` : 'Aucune propriété sélectionnée';
return msg;

// Route les actions venant du tableau
// - met à jour flow.propSelected
// - envoie seulement la propriété et les instances nécessaires aux éditeurs

let action = msg.action;
let prop = msg.prop || {};
let varSelected = flow.get('varSelected');
let enriched = global.get('enrichedVars','file') || {};
let variable = enriched[varSelected] || {};
let instances = (variable.instances || []).filter(i => i !== '*'); // instances visibles (sans '*')

if (action) {
    // set selected property for continuity
    flow.set('propSelected', prop && prop.nomP ? prop.nomP : null);
}

if (action === 'base') {
    // Forward to base editor (for define). include originalName if editing existing
    let out = { topic: 'openEditor', editor: 'base', prop: prop, instances: instances, originalName: prop && prop._isNew ? null : (prop && prop.nomP ? prop.nomP : null) };
    return [out, null, null];
}
else if (action === 'valeurs') {
    // forward minimal payload to values editor
    let out = { topic: 'openEditor', editor: 'valeurs', prop: prop, instances: instances, originalName: prop && prop.nomP ? prop.nomP : null };
    return [null, out, null];
}
else if (action === 'delete') {
    // forward to delete handler
    let out = { topic: 'delete', prop: prop };
    return [null, null, out];
}
return null;

// Reçoit les messages de tpl_base et tpl_values
// route selon msg.topic
// outputs: [saveProperty, saveValues, refreshTable]

if(!msg || !msg.topic) return null;
if(msg.topic === 'saveBase' || msg.topic === 'saveBaseWithSchema'){
    // forward to saveProperty
    msg.saveKind = (msg.topic === 'saveBaseWithSchema') ? 'baseWithSchema' : 'base';
    return [msg, null, null];
}
if(msg.topic === 'saveValues'){
    return [null, msg, null];
}
if(msg.topic === 'cancel'){
    // reset selected prop
    flow.set('propSelected', null);
    // request refresh
    let out = { topic: 'refresh' };
    return [null, null, out];
}
return null;

// Sauvegarde d'une propriété (base simple ou baseWithSchema)
// gère création ou mise à jour, verrouillage après schema

function defaultValForType(t){ if(t==='number') return 0; if(t==='boolean') return false; return ''; }

let varSelected = flow.get('varSelected');
let enriched = global.get('enrichedVars','file') || {};
let variable = enriched[varSelected] || { instances: ['*'] };
let prop = msg.prop || {};
let original = msg.originalName || null;
let saveKind = msg.saveKind || msg.topic;

// Backup
let backups = global.get('enrichedVars_backups','file') || [];
backups.push({ ts: new Date().toISOString(), snapshot: JSON.parse(JSON.stringify(enriched)) });
global.set('enrichedVars_backups', backups, 'file');

let idx = (variable.proprietes||[]).findIndex(p => p.nomP === original);

if(saveKind === 'base'){
    // simple type base (string/number/boolean)
    if(idx >= 0){
        // if locked -> refuse
        if(variable.proprietes[idx]._locked){ msg.info = '⚠️ Propriété verrouillée — modification de base interdite.'; return { topic:'refresh', info: msg.info }; }
        variable.proprietes[idx].nomP = prop.nomP || variable.proprietes[idx].nomP;
        variable.proprietes[idx].abbrP = prop.abbrP || variable.proprietes[idx].abbrP;
        variable.proprietes[idx].typeP = prop.typeP || variable.proprietes[idx].typeP;
        variable.proprietes[idx].schema = null;
    } else {
        // create new property simple
        let newp = { nomP: prop.nomP, abbrP: prop.abbrP||'', typeP: prop.typeP||'string', schema:null, valeurs:{} , _locked:false };
        (variable.instances || ['*']).forEach(i => newp.valeurs[i] = null);
        variable.proprietes = variable.proprietes || [];
        variable.proprietes.push(newp);
    }
}
else if(saveKind === 'baseWithSchema'){
    // object/array with schema -> set schema and LOCK definition
    let schema = prop.schema || [];
    if(idx >= 0){
        if(variable.proprietes[idx]._locked){ msg.info = '⚠️ Propriété verrouillée — modification du schéma interdite.'; return { topic:'refresh', info: msg.info }; }
        variable.proprietes[idx].nomP = prop.nomP || variable.proprietes[idx].nomP;
        variable.proprietes[idx].abbrP = prop.abbrP || variable.proprietes[idx].abbrP;
        variable.proprietes[idx].typeP = prop.typeP || variable.proprietes[idx].typeP;
        variable.proprietes[idx].schema = schema;
        variable.proprietes[idx]._locked = true;
        // initialize valeurs structure if missing
        let def = {};
        schema.forEach(s => def[s.nomSsP] = defaultValForType(s.typeSsP));
        variable.proprietes[idx].valeurs = variable.proprietes[idx].valeurs || {};
        (variable.instances || ['*']).forEach(i => { if(variable.proprietes[idx].valeurs[i] === undefined) variable.proprietes[idx].valeurs[i] = JSON.parse(JSON.stringify(def)); });
        variable.proprietes[idx].valeurs['*'] = JSON.parse(JSON.stringify(def));
    } else {
        // create new prop and lock
        let def = {};
        schema.forEach(s => def[s.nomSsP] = defaultValForType(s.typeSsP));
        let newp = { nomP: prop.nomP, abbrP: prop.abbrP||'', typeP: prop.typeP||'object', schema: schema, _locked:true, valeurs: {} };
        (variable.instances || ['*']).forEach(i => newp.valeurs[i] = JSON.parse(JSON.stringify(def)));
        newp.valeurs['*'] = JSON.parse(JSON.stringify(def));
        variable.proprietes = variable.proprietes || [];
        variable.proprietes.push(newp);
    }
}

// persist
enriched[varSelected] = variable;
global.set('enrichedVars', enriched, 'file');
flow.set('propSelected', (prop && prop.nomP) ? prop.nomP : null);
msg.info = `✅ Propriété enregistrée (${saveKind}).`;
// trigger refresh of table
return { topic:'refresh', view:'tableau', info: msg.info };

// Sauvegarde des valeurs par instance pour une propriété donnée
let varSelected = flow.get('varSelected');
let enriched = global.get('enrichedVars','file') || {};
let variable = enriched[varSelected] || {};
let prop = msg.prop || {};
if(!prop.nomP){ msg.info = '❌ Données incomplètes pour la sauvegarde des valeurs.'; return { topic:'refresh', info: msg.info }; }
let idx = (variable.proprietes||[]).findIndex(p => p.nomP === prop.nomP);
if(idx === -1){ msg.info='❌ Propriété introuvable.'; return { topic:'refresh', info: msg.info }; }

// backup
let backups = global.get('enrichedVars_backups','file') || [];
backups.push({ ts:new Date().toISOString(), snapshot: JSON.parse(JSON.stringify(enriched)) });
global.set('enrichedVars_backups', backups, 'file');

variable.proprietes[idx].valeurs = prop.valeurs || variable.proprietes[idx].valeurs || {};

global.set('enrichedVars', enriched, 'file');
flow.set('propSelected', prop.nomP);
msg.info = `✅ Valeurs mises à jour pour ${prop.nomP}`;
return { topic:'refresh', view:'tableau', info: msg.info };

// Supprime une propriété, création d'un backup
let varSelected = flow.get('varSelected');
let enriched = global.get('enrichedVars','file') || {};
let variable = enriched[varSelected] || {};
let prop = msg.prop || {};
if(!prop.nomP){ msg.info='❌ Propriété non fournie.'; return { topic:'refresh', info: msg.info }; }
// backup
let backups = global.get('enrichedVars_backups','file') || [];
backups.push({ ts:new Date().toISOString(), snapshot: JSON.parse(JSON.stringify(enriched)) });
global.set('enrichedVars_backups', backups, 'file');

variable.proprietes = (variable.proprietes||[]).filter(p => p.nomP !== prop.nomP);
enriched[varSelected] = variable;
global.set('enrichedVars', enriched, 'file');
flow.set('propSelected', null);
msg.info = `✅ Propriété supprimée : ${prop.nomP}`;
return { topic:'refresh', view:'tableau', info: msg.info };
